Функция ДебетовыйОборотПоСчётуИКонтрагенту(СсылкаНаСчёт, СсылкаНаКонтрагента)
    Запрос = Новый Запрос;
    Запрос.Текст =
        "ВЫБРАТЬ СУММА(Хозрасчетный.ДебетСумма) КАК СуммаПроводок
         ИЗ 
             РегистрБухгалтерии.Хозрасчетный Движения ССубконто КАК Хозрасчетный
         ГДЕ
             Хозрасчетный.СчетДт = &СчетДт
             И ((Хозрасчетный.СубконтоДт1 = &Контрагент)
                ИЛИ (Хозрасчетный.СубконтоДт2 = &Контрагент))";

    Запрос.УстановитьПараметр("СчетДт", СсылкаНаСчёт);
    Запрос.УстановитьПараметр("Контрагент", СсылкаНаКонтрагента);

    РезультатЗапроса = Запрос.Выполнить();
    ВыборкаДетальныеЗаписи = РезультатЗапроса.Выбрать();

    Если ВыборкаДетальныеЗаписи.Количество() > 0 Тогда
        ВыборкаДетальныеЗаписи.Следующий();
        Возврат ВыборкаДетальныеЗаписи.СуммаПроводок;
    Иначе
        Возврат 0;
    КонецЕсли;
КонецФункции
